    #${uniqueFormId} .consent-group { margin-bottom: 0; }
    #${uniqueFormId} .consent-group .checkbox-wrapper { padding: 0.5rem 0.75rem; }
    #${uniqueFormId} .consent-group label { font-size: 0.8rem; font-weight: normal; color: var(--label-color); }
